const spt = await stripe.createPaymentToken({
  amount: 5000,
  currency: 'usd'
});
// Returns: { id: 'spt_1N...' }

const spt = await stripe.createPaymentToken({
  amount: 100000,
  currency: 'usd'
});

const setupIntent = await stripe.confirmSetup({
  elements,
  confirmParams: {
    return_url: 'https://example.com/setup-complete'
  }
});
// Returns setup_intent_id that client includes in credential

