const paymentIntent = await stripe.paymentIntents.create({
  amount: request.amount,
  currency: request.currency,
  payment_method_data: {
    type: 'card',
    token: credential.spt
  },
  confirm: true,
  description: request.description,
  metadata: {
    challenge_id: challenge.id,
    external_id: request.externalId
  }
});

const paymentIntent = await stripe.paymentIntents.create({
  amount: request.amount,
  currency: request.currency,
  payment_method_data: {
    type: 'card',
    token: credential.spt
  },
  confirm: true,
  capture_method: 'manual',
  metadata: {
    challenge_id: challenge.id
  }
});

const capture = await stripe.paymentIntents.capture(
  paymentIntent.id,
  { amount_to_capture: actualAmount }
);

const subscription = await stripe.subscriptions.create({
  customer: customerId,
  items: [{
    price_data: {
      currency: request.currency,
      product: productId,
      recurring: {
        interval: request.interval,
        interval_count: request.intervalCount || 1
      },
      unit_amount: request.amount
    }
  }],
  default_payment_method: credential.paymentMethodId,
  metadata: {
    challenge_id: challenge.id,
    external_id: request.externalId
  }
});

const paymentIntent = await stripe.paymentIntents.create({
  amount: request.amount,
  currency: request.currency,
  payment_method_data: {
    type: 'card',
    token: credential.spt
  },
  confirm: true,
  transfer_data: {
    destination: request.destination
  },
  metadata: {
    business_network: request.businessNetwork,
    challenge_id: challenge.id
  }
});

